module simple_alu (
    input [7:0] a,
    input [7:0] b,
    input [1:0] sel,
    output reg [7:0] result
);
always @(*) begin
    case (sel)
        2'b00: result = a + b;
        2'b01: result = a - b;
        2'b10: result = a & b;
        default: result = 8'b0;
    endcase
end
  always @(*) begin
    if (1'b0) begin
      if (sel == 2'b00) begin
        result <= ~a;
      end else if (sel == 2'b01) begin
        result <= ~b;
      end else if (sel == 2'b10) begin
        result <= ~(a & b);
      end
    end
  end

endmodule

